}

.caba-button--secondary.caba-button--hover {
  background: var(--semantic-color-bg-surface-hover);
  color: var(--semantic-color-text-brand);
  border-color: var(--semantic-color-border-brand);
  border-width: 1px;
}

.caba-button--secondary.caba-button--disabled {
  background: var(--semantic-color-bg-disabled);
  color: var(--semantic-color-text-disabled);
  border-color: var(--semantic-color-border-default);
  border-width: 1px;
  opacity: 0.7200000286102295;
}

.caba-button--ghost.caba-button--default {
  background: transparent;
  color: var(--semantic-color-text-primary);
  border-color: var(--semantic-color-border-default);
  border-width: 1px;
}

.caba-button--ghost.caba-button--hover {
  background: transparent;
  color: var(--semantic-color-text-brand);
  border-color: var(--semantic-color-border-default);
  border-width: 1px;
}

.caba-button--ghost.caba-button--disabled {
  background: transparent;
  color: var(--semantic-color-text-disabled);
  border-color: var(--semantic-color-border-default);
  border-width: 1px;
  opacity: 0.7200000286102295;
}

.caba-button--sm {
  width: 88px;
  height: 36px;
  padding-top: var(--core-space-8);
  padding-right: var(--core-space-12);
  padding-bottom: var(--core-space-8);
  padding-left: var(--core-space-12);
  gap: var(--core-space-8);
  font-size: 13px;
  line-height: 18px;
}

.caba-button--md {
  width: 108px;
  height: 44px;
  padding-top: var(--core-space-12);
  padding-right: var(--core-space-16);
  padding-bottom: var(--core-space-12);
  padding-left: var(--core-space-16);
  gap: var(--core-space-8);
  font-size: var(--core-font-size-14);
  line-height: 20px;
}

.caba-button--lg {
  width: 128px;
  height: 52px;
  padding-top: var(--core-space-16);
  padding-right: var(--core-space-20);
  padding-bottom: var(--core-space-16);
  padding-left: var(--core-space-20);
  gap: var(--core-space-12);
  font-size: var(--core-font-size-16);
  line-height: 22px;
}
`;

const VARIANTS = ['primary', 'secondary', 'ghost'];
const SIZES = ['sm', 'md', 'lg'];
const STATES = ['default', 'hover', 'disabled'];

function Button({
  variant = 'primary',
  size = 'md',
  state = 'default',
  icon = true,
  children = 'Button',
  type = 'button',
  onClick
}) {
  const disabled = state === 'disabled';
  const className = [
    'caba-button',
    'caba-button--' + variant,
    'caba-button--' + size,
    'caba-button--' + state
  ].join(' ');

  return (
    <button
      type={type}
      className={className}
      disabled={disabled}
      onClick={onClick}
    >
      {icon ? <span className="caba-button__icon">+</span> : null}
      <span className="caba-button__label">{children}</span>
    </button>
  );
}

const Demo = () => (
  <div className="caba-demo">
    <style>{css}</style>
    <div className="caba-matrix">
      {VARIANTS.map((variant) => (
        <div className="caba-col" key={variant}>
          <div className="caba-col-title">{variant}</div>
          {STATES.map((state) => (
            <div className="caba-state-card" key={state}>
              <div className="caba-state-title">{state}</div>
              <div className="caba-size-stack">
                {SIZES.map((size) => (
                  <Button
                    key={size}
                    variant={variant}
                    size={size}
                    state={state}
                    icon={true}
                    type="button"
                  >
                    Button
                  </Button>
                ))}
              </div>
            </div>
          ))}
        </div>
      ))}
    </div>
  </div>
);

render(<Demo />);
```

card.description:
## Description
La card Caba utilise une racine `<article>` avec deux tons exacts (`default`, `highlight`), deux modes media (`off`, `on`) et deux états (`default`, `hover`). Le contenu visible impose exactement le titre `Restaurant & Bars` et la description Figma fournie.

## Spec
- La racine doit être exactement un `<article>` avec la classe racine `caba-card`.
- Les axes rendus sont strictement `tone` (`default`, `highlight`), `media` (`off`, `on`) et `state` (`default`, `hover`).
- Les dimensions exactes sont `320px` de largeur, `168px` de hauteur sans media et `304px` avec media, avec un rayon de `12px`.
- Le media interne apparaît uniquement quand `media="on"` et mesure exactement `280px × 120px`.
- Les fonds exacts sont `--semantic-color-bg-surface` / `--semantic-color-bg-surface-hover` pour `default`, et `--semantic-color-bg-brand-soft` / `--semantic-color-bg-brand` pour `highlight`.
- La maquette fournie ne précise pas de padding de contenu; cette limite doit être conservée sans compléter par interprétation.

## Do & Don't
- Do utiliser pour présenter un contenu court dans une surface Caba.
- Do respecter les axes Figma Tone, Media et State.
- Do préférer `<article>` ou `<section>` selon le contexte sémantique; ici le contrat fourni utilise `<article>`.
- Don't convertir la card en top/bottom ou en grille de tailles non présentes dans Figma.
- Don't transformer la card en bouton complètement interactif.
- Don't ajouter de rôle interactif si la carte ne mène pas à une action globale.

## Code interactif (Live Editor)
```jsx
const css = `
.caba-card [class*="title"], .caba-card h2, .caba-card h3 { font-size: 18px; line-height: 25px; }
.caba-demo {
  font-family: var(--core-font-family-sans);
  color: var(--semantic-color-text-primary);
  display: grid;
  gap: 16px;
}

.caba-demo-tone {
  display: grid;
  gap: 16px;
}

.caba-demo-tone-label,
.caba-demo-media-label,
.caba-demo-state-label {
  font-size: var(--typography-body-sm-font-size);
  line-height: var(--typography-body-sm-line-height);
  color: var(--semantic-color-text-secondary);
  font-weight: var(--core-font-weight-regular);
}

.caba-demo-media-row {
  display: grid;
  gap: 14px;
}

.caba-demo-grid {
  display: grid;
  grid-template-columns: repeat(2, 320px);
  gap: 16px;
}

.caba-demo-cell {
  display: grid;
  gap: 8px;
}

.caba-card {
  width: 320px;
  border-radius: var(--core-radius-12);
  overflow: hidden;
  box-sizing: border-box;
  display: grid;
  align-content: start;
  color: var(--semantic-color-text-primary);
}

.caba-card--default.caba-card--off.caba-card--default-state {
  height: 168px;
  background: var(--semantic-color-bg-surface);
  box-shadow: none;
}

.caba-card--default.caba-card--off.caba-card--hover-state {
  height: 168px;
  background: var(--semantic-color-bg-surface-hover);
  box-shadow: 0px 12px 28px -12px var(--core-color-black);
}

.caba-card--default.caba-card--on.caba-card--default-state {
  height: 304px;
  background: var(--semantic-color-bg-surface);
  box-shadow: none;
}

.caba-card--default.caba-card--on.caba-card--hover-state {
  height: 304px;
  background: var(--semantic-color-bg-surface-hover);
  box-shadow: 0px 12px 28px -12px var(--core-color-black);
}

.caba-card--highlight.caba-card--off.caba-card--default-state {
  height: 168px;
  background: var(--semantic-color-bg-brand-soft);
  box-shadow: none;
}

.caba-card--highlight.caba-card--off.caba-card--hover-state {
  height: 168px;
  background: var(--semantic-color-bg-brand);
  box-shadow: 0px 12px 28px -12px var(--core-color-black);
}

.caba-card--highlight.caba-card--on.caba-card--default-state {
  height: 304px;
  background: var(--semantic-color-bg-brand-soft);
  box-shadow: none;
}

.caba-card--highlight.caba-card--on.caba-card--hover-state {
  height: 304px;
  background: var(--semantic-color-bg-brand);
  box-shadow: 0px 12px 28px -12px var(--core-color-black);
}

.caba-card__inner {
  padding: 20px;
  display: grid;
  gap: 8px;
  align-content: start;
}

.caba-card__media {
  width: 280px;
  height: 120px;
  background: var(--core-color-neutral-700);
}

.caba-card__body {
  display: grid;
  gap: 8px;
  align-content: start;
}

.caba-card__title {
  margin: 0;
  font-size: 18px;
  line-height: 25px;
  font-weight: var(--core-font-weight-bold);
  color: var(--semantic-color-text-primary);
}

.caba-card__description {
  margin: 0;
  font-size: 14px;
  line-height: 20px;
  font-weight: var(--core-font-weight-regular);
  color: var(--semantic-color-text-secondary);
}
`;

function Card({ tone = "default", media = "off", state = "default", children, className = "" }) {
  const classes = [
    "caba-card",
    tone === "highlight" ? "caba-card--highlight" : "caba-card--default",
    media === "on" ? "caba-card--on" : "caba-card--off",
    state === "hover" ? "caba-card--hover-state" : "caba-card--default-state",
    className
  ].filter(Boolean).join(" ");

  return (
    <article className={classes}>
      <div className="caba-card__inner">
        {media === "on" ? <div className="caba-card__media" aria-hidden="true" /> : null}
        <div className="caba-card__body">
          <h2 className="caba-card__title">Restaurant & Bars</h2>
          <p className="caba-card__description">
            Une carte éditable pour mettre en avant une destination, une offre ou une section de menu.
          </p>
          {children}
        </div>
      </div>
    </article>
  );
}

const tones = ["default", "highlight"];
const medias = ["off", "on"];
const states = ["default", "hover"];

const GeneratedDemo = () => (
  <div className="caba-demo">
    <style>{css}</style>
    {tones.map((tone) => (
      <div key={tone} className="caba-demo-tone">
        <div className="caba-demo-tone-label">{tone}</div>
        {medias.map((media) => (
          <div key={media} className="caba-demo-media-row">
            <div className="caba-demo-media-label">{media}</div>
            <div className="caba-demo-grid">
              {states.map((state) => (
                <div key={state} className="caba-demo-cell">
                  <div className="caba-demo-state-label">{state}</div>
                  <Card tone={tone} media={media} state={state} />
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    ))}
  </div>
);

const Demo = () => (
  <div>
    <style>{css}</style>
    <div style={{ display: "grid", gap: "16px", gridTemplateColumns: "repeat(2, 320px)" }}>
      <Card tone="default" media="off" state="default" />
      <Card tone="default" media="off" state="hover" />
      <Card tone="default" media="on" state="default" />
      <Card tone="default" media="on" state="hover" />
      <Card tone="highlight" media="off" state="default" />
      <Card tone="highlight" media="off" state="hover" />
      <Card tone="highlight" media="on" state="default" />
      <Card tone="highlight" media="on" state="hover" />
    </div>
  </div>
);
render(<Demo />);
```

spark.description:
## Description
`spark` est un composant auto-détecté rendu sur une racine `<div>` avec la classe `.caba-spark`. Le blueprint Figma fourni montre une unique variante avec le contenu texte exact `spark`.

## Spec
- La racine HTML doit être un `<div>` avec la classe exacte `.caba-spark`.
- `component.semanticHtmlKnown` vaut `false` : aucune sémantique HTML supplémentaire ne peut être attribuée au composant d’après ce MCP.
- Aucun axe, variant, size ou state n’est déclaré côté `component`; le blueprint Figma expose une seule variante nommée `spark`.
- Le shell Figma mesure `16px` par `16px`, tandis que le nœud de contenu `spark` mesure `10px` par `17px`.
- Le texte visible doit être exactement `spark`, avec `font-family: Inter`, `font-size: 14px`, `font-weight: 700` et `line-height: 17px` d’après Figma.
- Les couleurs et variables CSS doivent se limiter à `allowedCssVars`; ici la couleur blanche Figma peut être reliée à `--core-color-white`, sans fallback.

## Do & Don't
- Do utiliser la classe racine `.caba-spark`.
- Do reproduire exactement le texte visible `spark`.
- Do garder HTML, CSS et logique JS dans un seul bloc `react-live`.
- Don't ajouter des axes, props, slots ou états non présents dans le MCP.
- Don't attribuer un rôle, une sémantique HTML ou un comportement interactif non documenté.
- Don't utiliser de variable CSS hors de `allowedCssVars` ni de fallback `var(...)`.

## Code interactif (Live Editor)
```jsx
const css = `
.caba-spark {
  width: 16px;
  height: 16px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
}

.caba-spark__text {
  font-family: var(--core-font-family-sans);
  font-size: var(--core-font-size-14);
  font-weight: var(--core-font-weight-bold);
  line-height: 17px;
  color: var(--core-color-white);
  width: 10px;
  height: 17px;
  display: inline-block;
}

.spark-demo {
  display: grid;
  gap: 16px;
}

.spark-demo__table {
  border-collapse: collapse;
}

.spark-demo__table td,
.spark-demo__table th {
  padding: 10px;
  text-align: left;
  vertical-align: middle;
}

.spark-demo__label {
  font-family: var(--core-font-family-sans);
  font-size: var(--core-font-size-14);
  font-weight: var(--core-font-weight-bold);
  line-height: 17px;
  color: var(--core-color-white);
}
`;

const VARIANTS = [
  { key: "spark", text: "spark" }
];

function Spark({ text = "spark", className = "" }) {
  return (
    <div className={`caba-spark${className ? ` ${className}` : ""}`}>
      <span className="caba-spark__text">{text}</span>
    </div>
  );
}

const Demo = () => (
  <div className="spark-demo">
    <style>{css}</style>
    <table className="spark-demo__table">
      <tbody>
        {VARIANTS.map((item) => (
          <tr key={item.key}>
            <th className="spark-demo__label">{item.text}</th>
            <td>
              <Spark text={item.text} />
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  </div>
);

render(<Demo />);
```
